// ─── ChatComposer ─────────────────────────────────────────────────────────────

interface ChatComposerProps {
  onSend?: (text: string) => void
  onTyping?: (isTyping: boolean) => void
  onFileUpload?: (files: File[]) => void
  onVoiceRecord?: () => void
  placeholder?: string
  disabled?: boolean
  replyingTo?: ChatMessageData | null
  onCancelReply?: () => void
  className?: string
}

function ChatComposer({
  onSend,
  onTyping,
  onFileUpload,
  onVoiceRecord,
  placeholder = "Message",
  disabled = false,
  replyingTo,
  onCancelReply,
  className,
}: ChatComposerProps) {
  const [value, setValue] = React.useState("")
  const [files, setFiles] = React.useState<FilePreviewItem[]>([])
  const [isDragging, setIsDragging] = React.useState(false)
  const [showAttachMenu, setShowAttachMenu] = React.useState(false)
  const { textareaRef, resize } = useAutoResize({ maxRows: 6 })
  const { handleKeyDown: handleTypingKeyDown, stopTyping } =
    useTypingIndicator({ onTypingChange: onTyping })
  const fileInputRef = React.useRef<HTMLInputElement>(null)
  const imageInputRef = React.useRef<HTMLInputElement>(null)
  const hasContent = value.trim().length > 0 || files.length > 0

  const addFiles = React.useCallback((newFiles: FileList | File[]) => {
    const arr = Array.from(newFiles)
    const items: FilePreviewItem[] = arr.map((f) => ({
      file: f,
      id: `${f.name}-${Date.now()}-${Math.random()}`,
      progress: undefined,
    }))

    // Generate image previews
    items.forEach((item) => {
      if (item.file.type.startsWith("image/")) {
        const reader = new FileReader()
        reader.onload = (e) => {
          setFiles((prev) =>
            prev.map((f) => f.id === item.id ? { ...f, preview: e.target?.result as string } : f)
          )
        }
        reader.readAsDataURL(item.file)
      }
    })

    setFiles((prev) => [...prev, ...items])
    onFileUpload?.(arr)
  }, [onFileUpload])

  const removeFile = React.useCallback((id: string) => {
    setFiles((prev) => prev.filter((f) => f.id !== id))
  }, [])

  const handleSend = React.useCallback(() => {
    const trimmed = value.trim()
    if ((!trimmed && files.length === 0) || disabled) return
    if (trimmed) onSend?.(trimmed)
    setValue("")
    setFiles([])
    stopTyping()
    if (textareaRef.current) textareaRef.current.style.height = "auto"
  }, [value, files, disabled, onSend, textareaRef, stopTyping])

  const handleKeyDown = React.useCallback(
    (e: React.KeyboardEvent) => {
      handleTypingKeyDown()
      if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend() }
      if (e.key === "Escape" && replyingTo) onCancelReply?.()
    },
    [handleSend, handleTypingKeyDown, replyingTo, onCancelReply]
  )

  // Paste upload
  const handlePaste = React.useCallback(
    (e: React.ClipboardEvent) => {
      const items = e.clipboardData?.items
      if (!items) return
      const imageFiles: File[] = []
      for (const item of Array.from(items)) {
        if (item.type.startsWith("image/")) {
          const file = item.getAsFile()
          if (file) imageFiles.push(file)
        }
      }
      if (imageFiles.length > 0) {
        addFiles(imageFiles)
        setShowAttachMenu(false)
      }
    },
    [addFiles]
  )

  // Drag-and-drop handlers (on the composer container)
  const handleDragOver = React.useCallback((e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(true)
  }, [])
  const handleDragLeave = React.useCallback((e: React.DragEvent) => {
    e.preventDefault()
    setIsDragging(false)
  }, [])
  const handleDrop = React.useCallback(
    (e: React.DragEvent) => {
      e.preventDefault()
      setIsDragging(false)
      if (e.dataTransfer.files.length > 0) {
        addFiles(e.dataTransfer.files)
        setShowAttachMenu(false)
      }
    },
    [addFiles]
  )

  return (
    <div
      className={cn("chat-composer sticky bottom-0 z-10 relative", className)}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {/* Drop overlay */}
      {isDragging && (
        <div className="chat-drop-overlay">
          <div className="flex flex-col items-center gap-2">
            <Upload className="size-8 text-[var(--chat-accent)]" />
            <span className="text-[14px] font-medium text-[var(--chat-accent)]">Drop files to upload</span>
          </div>
        </div>
      )}

      {/* Reply preview bar */}
      {replyingTo && (
        <ChatReplyPreview replyingTo={replyingTo} onCancel={() => onCancelReply?.()} />
      )}

      {/* File preview strip */}
      {files.length > 0 && (
        <div className="flex gap-3 overflow-x-auto border-t border-[var(--chat-border)] bg-[var(--chat-bg-composer)] px-4 pt-3 pb-2 backdrop-blur-[20px]">
          {files.map((f) => (
            <ChatFilePreview key={f.id} item={f} onRemove={() => removeFile(f.id)} />
          ))}
        </div>
      )}

      {/* Composer body — frosted glass */}
      <div className="border-t border-[var(--chat-border)] bg-[var(--chat-bg-composer)] px-3 py-2 backdrop-blur-[20px] backdrop-saturate-[180%]">
        <div className="mx-auto max-w-3xl">
          {/* Input row */}
          <div className="flex items-end gap-2">
            {/* + button with attachment popout */}
            <div className="relative">
              <button
                onClick={() => setShowAttachMenu(!showAttachMenu)}
                className={cn(
                  "flex size-9 items-center justify-center rounded-full border border-[var(--chat-border)] bg-[var(--chat-bg-sidebar)] text-[var(--chat-text-tertiary)] transition-all hover:bg-[var(--chat-accent-soft)] hover:text-[var(--chat-text-secondary)]",
                  showAttachMenu && "rotate-45 bg-[var(--chat-accent-soft)] text-[var(--chat-accent)]"
                )}
                aria-label="Attachments"
              >
                <Plus className="size-5" />
              </button>

              {/* Popout menu */}
              {showAttachMenu && (
                <div className="chat-toolbar-enter absolute bottom-full left-0 mb-2 w-44 overflow-hidden rounded-xl border border-[var(--chat-border-strong)] bg-[var(--chat-bg-sidebar)] py-1 shadow-[var(--chat-shadow-toolbar)]">
                  <button
                    onClick={() => { fileInputRef.current?.click(); setShowAttachMenu(false) }}
                    className="flex w-full items-center gap-2.5 px-3 py-2 text-[13px] text-[var(--chat-text-secondary)] transition-colors hover:bg-[var(--chat-accent-soft)] hover:text-[var(--chat-text-primary)]"
                  >
                    <Paperclip className="size-4" />
                    Attach file
                  </button>
                  <button
                    onClick={() => { imageInputRef.current?.click(); setShowAttachMenu(false) }}
                    className="flex w-full items-center gap-2.5 px-3 py-2 text-[13px] text-[var(--chat-text-secondary)] transition-colors hover:bg-[var(--chat-accent-soft)] hover:text-[var(--chat-text-primary)]"
                  >
                    <ImageIcon className="size-4" />
                    Photo or video
                  </button>
                  <button
                    onClick={() => setShowAttachMenu(false)}
                    className="flex w-full items-center gap-2.5 px-3 py-2 text-[13px] text-[var(--chat-text-secondary)] transition-colors hover:bg-[var(--chat-accent-soft)] hover:text-[var(--chat-text-primary)]"
                  >
                    <Smile className="size-4" />
                    Emoji
                  </button>
                </div>
              )}
            </div>

            {/* Hidden file inputs */}
            <input ref={fileInputRef} type="file" multiple className="hidden" onChange={(e) => { if (e.target.files) addFiles(e.target.files); e.target.value = "" }} />
            <input ref={imageInputRef} type="file" accept="image/*" multiple className="hidden" onChange={(e) => { if (e.target.files) addFiles(e.target.files); e.target.value = "" }} />

            <div className="relative flex flex-1 items-end rounded-[22px] border border-[var(--chat-border)] bg-[var(--chat-bg-sidebar)]">
              <textarea
                ref={textareaRef}
                value={value}
                onChange={(e) => { setValue(e.target.value); resize() }}
                onKeyDown={handleKeyDown}
                onPaste={handlePaste}
                placeholder={placeholder}
                disabled={disabled}
                rows={1}
                className="flex-1 resize-none bg-transparent py-[10px] pl-4 pr-12 text-[15px] leading-[22px] tracking-[-0.01em] text-[var(--chat-text-primary)] placeholder:text-[var(--chat-text-tertiary)] focus:outline-none disabled:opacity-50"
                style={{ overflow: "hidden", maxHeight: "160px" }}
              />

              {!hasContent && onVoiceRecord ? (
                <button
                  onClick={onVoiceRecord}
                  disabled={disabled}
                  className="absolute bottom-[6px] right-[6px] flex size-8 items-center justify-center rounded-full text-[var(--chat-text-tertiary)] transition-colors hover:text-[var(--chat-accent)]"
                  aria-label="Record voice message"
                >
                  <Mic className="size-4" strokeWidth={2.5} />
                </button>
              ) : (
                <button
                  onClick={handleSend}
                  disabled={!hasContent || disabled}
                  className={cn(
                    "absolute bottom-[6px] right-[6px] flex size-8 items-center justify-center rounded-full transition-all duration-200",
                    hasContent
                      ? "bg-[var(--chat-accent)] text-white hover:scale-105 active:scale-95"
                      : "bg-transparent text-[var(--chat-text-tertiary)]"
                  )}
                  aria-label="Send message"
                >
                  <ArrowUp className="size-4" strokeWidth={2.5} />
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  ChatProvider,
  ChatMessage,
  ChatMessageGroup,
  ChatDateSeparator,
  ChatSystemMessage,
  ChatMessages,
  ChatComposer,
  ChatMessageStatus,
  ChatMessageReactions,
  ChatMessageActions,
  ChatMessageReply,
  ChatTypingIndicator,
  ChatReplyPreview,
  ChatReadReceipts,
}
export type {
  ChatProviderProps,
  ChatMessageProps,
  ChatMessageGroupProps,
  ChatDateSeparatorProps,
  ChatSystemMessageProps,
  ChatMessagesProps,
  ChatComposerProps,
  ChatMessageActionsProps,
  ChatTypingIndicatorProps,
  ChatReplyPreviewProps,
}

export interface ChatUser {
  id: string
  name: string
  avatar?: string
  status?: "online" | "away" | "dnd" | "offline"
}

export interface ChatMessageData {
  id: string
  senderId: string
  senderName: string
  senderAvatar?: string

  // Content
  text?: string
  images?: { url: string; width: number; height: number; alt?: string }[]
  files?: { name: string; size: number; type: string; url: string }[]
  voice?: { url: string; duration: number; waveform: number[] }
  linkPreview?: {
    url: string
    title: string
    description: string
    image?: string
  }
  code?: { language: string; code: string }

  // Metadata
  timestamp: Date | number
  status?: "sending" | "sent" | "delivered" | "read" | "failed"
  replyTo?: { id: string; senderName: string; text: string }
  reactions?: { emoji: string; userIds: string[]; count: number }[]
  isEdited?: boolean
  isPinned?: boolean
  isSystem?: boolean
  systemEvent?: string

  // Read receipts (group chat) — list of users who have read up to this message
  readBy?: { userId: string; name: string; avatar?: string }[]
}

export interface ChatConfig {
  currentUser: ChatUser
  dateFormat?: "relative" | "absolute" | "time-only"
  messageGroupingInterval?: number // seconds, default 120

  // Callbacks
  onReactionAdd?: (messageId: string, emoji: string) => void
  onReactionRemove?: (messageId: string, emoji: string) => void
  onReply?: (message: ChatMessageData) => void
  onEdit?: (message: ChatMessageData) => void
  onDelete?: (messageId: string) => void
  onPin?: (messageId: string) => void
}

/** A group of consecutive messages from the same sender within the grouping interval */
export interface MessageGroup {
  senderId: string
  senderName: string
  senderAvatar?: string
  messages: ChatMessageData[]
  isOutgoing: boolean
}

/** Items that can appear in the message list */
export type MessageListItem =
  | { type: "group"; group: MessageGroup }
  | { type: "date"; date: Date; label: string }
  | { type: "system"; message: ChatMessageData }

/** Typing state for one or more users */
export interface TypingUser {
  id: string
  name: string
  avatar?: string
}

/** Available built-in themes */
export type ChatTheme = "lunar" | "aurora" | "ember" | "midnight"

"use client"

import {
  useRef,
  useEffect,
  useCallback,
  useState,
} from "react"
import {
  isToday,
  isYesterday,
  format,
  isSameDay,
  differenceInSeconds,
} from "date-fns"
import type { ChatMessageData, MessageListItem, MessageGroup } from "./types"

// ─── Date formatting ──────────────────────────────────────────────────────────

export function formatDateLabel(date: Date): string {
  if (isToday(date)) return "Today"
  if (isYesterday(date)) return "Yesterday"
  const now = new Date()
  const diffDays = Math.floor(
    (now.getTime() - date.getTime()) / (1000 * 60 * 60 * 24)
  )
  if (diffDays < 7) return format(date, "EEEE") // "Tuesday"
  if (date.getFullYear() === now.getFullYear())
    return format(date, "MMMM d") // "March 18"
  return format(date, "MMMM d, yyyy") // "March 18, 2026"
}

export function formatTimestamp(date: Date): string {
  return format(date, "h:mm a") // "10:42 AM"
}

// ─── Message grouping ─────────────────────────────────────────────────────────

export function groupMessages(
  messages: ChatMessageData[],
  currentUserId: string,
  intervalSeconds: number = 120
): MessageListItem[] {
  if (messages.length === 0) return []

  const items: MessageListItem[] = []
  let currentGroup: MessageGroup | null = null
  let lastDate: Date | null = null

  for (const msg of messages) {
    const msgDate = new Date(msg.timestamp)

    // System messages break groups
    if (msg.isSystem) {
      if (currentGroup) {
        items.push({ type: "group", group: currentGroup })
        currentGroup = null
      }

      // Insert date separator if needed
      if (!lastDate || !isSameDay(lastDate, msgDate)) {
        items.push({ type: "date", date: msgDate, label: formatDateLabel(msgDate) })
        lastDate = msgDate
      }

      items.push({ type: "system", message: msg })
      continue
    }

    // Insert date separator if needed
    if (!lastDate || !isSameDay(lastDate, msgDate)) {
      if (currentGroup) {
        items.push({ type: "group", group: currentGroup })
        currentGroup = null
      }
      items.push({ type: "date", date: msgDate, label: formatDateLabel(msgDate) })
      lastDate = msgDate
    }

    // Check if message should continue the current group
    const shouldGroup =
      currentGroup &&
      currentGroup.senderId === msg.senderId &&
      currentGroup.messages.length > 0 &&
      differenceInSeconds(
        msgDate,
        new Date(
          currentGroup.messages[currentGroup.messages.length - 1].timestamp
        )
      ) <= intervalSeconds

    if (shouldGroup && currentGroup) {
      currentGroup.messages.push(msg)
    } else {
      if (currentGroup) {
        items.push({ type: "group", group: currentGroup })
      }
      currentGroup = {
        senderId: msg.senderId,
        senderName: msg.senderName,
        senderAvatar: msg.senderAvatar,
        messages: [msg],
        isOutgoing: msg.senderId === currentUserId,
      }
    }
  }

  if (currentGroup) {
    items.push({ type: "group", group: currentGroup })
  }

  return items
}

// ─── Auto-scroll hook ─────────────────────────────────────────────────────────

export function useAutoScroll(
  messages: ChatMessageData[],
  opts?: { threshold?: number }
) {
  const containerRef = useRef<HTMLDivElement>(null)
  const [isAtBottom, setIsAtBottom] = useState(true)
  const [unseenCount, setUnseenCount] = useState(0)
  const prevLengthRef = useRef(messages.length)
  const threshold = opts?.threshold ?? 100

  const scrollToBottom = useCallback(
    (behavior: ScrollBehavior = "smooth") => {
      const el = containerRef.current
      if (!el) return
      el.scrollTo({ top: el.scrollHeight, behavior })
      setUnseenCount(0)
    },
    []
  )

  // Track scroll position
  useEffect(() => {
    const el = containerRef.current
    if (!el) return

    const handleScroll = () => {
      const distanceFromBottom =
        el.scrollHeight - el.scrollTop - el.clientHeight
      const atBottom = distanceFromBottom <= threshold
      setIsAtBottom(atBottom)
      if (atBottom) setUnseenCount(0)
    }

    el.addEventListener("scroll", handleScroll, { passive: true })
    return () => el.removeEventListener("scroll", handleScroll)
  }, [threshold])

  // Auto-scroll when new messages arrive and user is at bottom
  useEffect(() => {
    const newCount = messages.length - prevLengthRef.current
    prevLengthRef.current = messages.length

    if (newCount <= 0) return

    if (isAtBottom) {
      scrollToBottom("smooth")
    } else {
      setUnseenCount((c) => c + newCount)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [messages.length])

  // Scroll to bottom on mount
  useEffect(() => {
    scrollToBottom("instant")
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  return { containerRef, scrollToBottom, isAtBottom, unseenCount } as const
}

// ─── Auto-resize textarea hook ────────────────────────────────────────────────

export function useAutoResize(opts?: { maxRows?: number }) {
  const textareaRef = useRef<HTMLTextAreaElement>(null)
  const maxRows = opts?.maxRows ?? 6

  const resize = useCallback(() => {
    const el = textareaRef.current
    if (!el) return
    el.style.height = "auto"
    const lineHeight = parseInt(getComputedStyle(el).lineHeight) || 22
    const maxHeight = lineHeight * maxRows
    el.style.height = `${Math.min(el.scrollHeight, maxHeight)}px`
    el.style.overflowY = el.scrollHeight > maxHeight ? "auto" : "hidden"
  }, [maxRows])

  return { textareaRef, resize } as const
}

// ─── Typing indicator hook ────────────────────────────────────────────────────

export function useTypingIndicator(opts?: {
  onTypingChange?: (isTyping: boolean) => void
  debounceMs?: number
}) {
  const [isTyping, setIsTyping] = useState(false)
  const timeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const debounceMs = opts?.debounceMs ?? 2000

  const handleKeyDown = useCallback(() => {
    if (!isTyping) {
      setIsTyping(true)
      opts?.onTypingChange?.(true)
    }

    if (timeoutRef.current) clearTimeout(timeoutRef.current)
    timeoutRef.current = setTimeout(() => {
      setIsTyping(false)
      opts?.onTypingChange?.(false)
    }, debounceMs)
  }, [isTyping, debounceMs, opts])

  const stopTyping = useCallback(() => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current)
    setIsTyping(false)
    opts?.onTypingChange?.(false)
  }, [opts])

  useEffect(() => {
    return () => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current)
    }
  }, [])

  return { isTyping, handleKeyDown, stopTyping } as const
}

/**
 * chatcn — Security Utilities
 * XSS prevention, URL sanitization, file validation, bidi stripping, emoji validation
 */

// ─── URL Sanitization ─────────────────────────────────────────────────────────

const ALLOWED_URL_PROTOCOL = /^(https?:\/\/|mailto:)/i

/** Sanitize a URL — only allow http, https, and mailto. Blocks javascript:, data:, etc. */
export function sanitizeUrl(url: string | undefined | null): string {
  if (!url) return "#"
  const trimmed = url.trim()
  if (!ALLOWED_URL_PROTOCOL.test(trimmed)) return "#"
  return trimmed
}

/** Extract hostname from a URL for display (prevents misleading long URLs) */
export function displayHostname(url: string): string {
  try {
    return new URL(url).hostname
  } catch {
    return url
  }
}

// ─── Text Sanitization ───────────────────────────────────────────────────────

/** Strip bidi override characters that can disguise malicious content (RLO attacks) */
export function stripBidiOverrides(text: string): string {
  // Remove LRO, RLO, LRE, RLE, PDF, LRI, RLI, FSI, PDI
  return text.replace(/[\u202A-\u202E\u2066-\u2069]/g, "")
}

/** Truncate message text to prevent rendering DoS */
export function truncateMessage(
  text: string,
  maxLength: number = 10_000
): { text: string; truncated: boolean } {
  if (text.length <= maxLength) return { text, truncated: false }
  return { text: text.slice(0, maxLength) + "\u2026", truncated: true }
}

/** Sanitize sender name — strip bidi, truncate */
export function sanitizeSenderName(name: string): string {
  return stripBidiOverrides(name).slice(0, 100)
}

// ─── File Validation ──────────────────────────────────────────────────────────

const BLOCKED_EXTENSIONS = new Set([
  ".exe", ".bat", ".cmd", ".scr", ".pif", ".com",
  ".js", ".jsx", ".ts", ".tsx", ".mjs",
  ".html", ".htm", ".xhtml",
  ".svg",
  ".xml", ".xsl", ".xslt",
  ".hta", ".vbs", ".vbe", ".wsf", ".wsh",
  ".ps1", ".psm1",
  ".sh", ".bash",
])

const DEFAULT_MAX_FILE_SIZE = 25 * 1024 * 1024 // 25MB

export interface FileValidationResult {
  valid: boolean
  error?: string
}

export function validateFile(
  file: File,
  opts?: { maxSize?: number }
): FileValidationResult {
  const maxSize = opts?.maxSize ?? DEFAULT_MAX_FILE_SIZE

  // Check extension
  const parts = file.name.split(".")
  const ext = parts.length > 1 ? "." + parts[parts.length - 1].toLowerCase() : ""
  if (BLOCKED_EXTENSIONS.has(ext)) {
    return { valid: false, error: `File type ${ext} is not allowed` }
  }

  // Check size
  if (file.size > maxSize) {
    const mbLimit = Math.round(maxSize / (1024 * 1024))
    return { valid: false, error: `File exceeds maximum size of ${mbLimit}MB` }
  }

  return { valid: true }
}

/** Sanitize a file name for display */
export function sanitizeFileName(name: string): string {
  let clean = name.replace(/[/\\]/g, "_")   // Remove path traversal
  clean = clean.replace(/\0/g, "")           // Remove null bytes
  clean = stripBidiOverrides(clean)           // Remove bidi overrides
  if (clean.length > 100) clean = clean.slice(0, 97) + "..."
  return clean
}

// ─── Emoji Validation ─────────────────────────────────────────────────────────

const EMOJI_REGEX = /^(\p{Emoji_Presentation}|\p{Emoji}\uFE0F)(\u200D(\p{Emoji_Presentation}|\p{Emoji}\uFE0F))*$/u

/** Validate that a string is a valid emoji (not arbitrary text) */
export function isValidEmoji(str: string): boolean {
  return EMOJI_REGEX.test(str) && str.length <= 20
}

// ─── Reaction Count Safety ────────────────────────────────────────────────────

/** Format reaction count for display (cap at 999+, floor at 0) */
export function formatReactionCount(count: number): string {
  if (count <= 0) return "0"
  if (count > 999) return "999+"
  return String(count)
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import {
  X,
  Search,
  Pin,
  ChevronDown,
  ChevronRight,
  ArrowUp,
  ArrowDown,
  Trash2,
  Check,
} from "lucide-react"
import type { ChatMessageData } from "./types"
import { formatTimestamp } from "./hooks"

// ─── ChatForwardDialog ────────────────────────────────────────────────────────

interface Conversation {
  id: string
  title: string
  avatar?: string
}

interface ChatForwardDialogProps {
  message: ChatMessageData
  conversations: Conversation[]
  onForward: (targetIds: string[]) => void
  onCancel: () => void
  className?: string
}

function ChatForwardDialog({
  message,
  conversations,
  onForward,
  onCancel,
  className,
}: ChatForwardDialogProps) {
  const [query, setQuery] = React.useState("")
  const [selected, setSelected] = React.useState<Set<string>>(new Set())

  const filtered = conversations.filter((c) =>
    c.title.toLowerCase().includes(query.toLowerCase())
  )

  const toggle = (id: string) => {
    setSelected((prev) => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      return next
    })
  }

  return (
    <div className={cn("fixed inset-0 z-50 flex items-center justify-center bg-black/50", className)}>
      <div className="w-full max-w-sm overflow-hidden rounded-xl border border-[var(--chat-border-strong)] bg-[var(--chat-bg-sidebar)] shadow-[var(--chat-shadow-lg)]">
        {/* Header */}
        <div className="flex items-center justify-between border-b border-[var(--chat-border)] px-4 py-3">
          <span className="text-[14px] font-semibold text-[var(--chat-text-primary)]">Forward message</span>
          <button onClick={onCancel} className="text-[var(--chat-text-tertiary)] hover:text-[var(--chat-text-primary)]">
            <X className="size-4" />
          </button>
        </div>

        {/* Preview */}
        <div className="border-b border-[var(--chat-border)] px-4 py-2">
          <span className="text-[12px] font-semibold text-[var(--chat-text-secondary)]">{message.senderName}</span>
          <p className="truncate text-[13px] text-[var(--chat-text-tertiary)]">{message.text}</p>
        </div>

        {/* Search */}
        <div className="border-b border-[var(--chat-border)] px-4 py-2">
          <div className="flex items-center gap-2 rounded-lg bg-[var(--chat-bg-main)] px-3 py-1.5">
            <Search className="size-3.5 text-[var(--chat-text-tertiary)]" />
            <input
              type="text"
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Search conversations..."
              className="flex-1 bg-transparent text-[13px] text-[var(--chat-text-primary)] placeholder:text-[var(--chat-text-tertiary)] outline-none"
            />
          </div>
        </div>

        {/* Conversation list */}
        <div className="max-h-60 overflow-y-auto">
          {filtered.map((c) => (
            <button
              key={c.id}
              onClick={() => toggle(c.id)}
              className={cn(
                "flex w-full items-center gap-3 px-4 py-2.5 text-left transition-colors",
                selected.has(c.id) ? "bg-[var(--chat-accent-soft)]" : "hover:bg-[var(--chat-accent-soft)]"
              )}
            >
              <div className="flex size-8 items-center justify-center rounded-full bg-[var(--chat-bubble-incoming)] text-[11px] font-semibold text-[var(--chat-text-secondary)]">
                {c.title.charAt(0).toUpperCase()}
              </div>
              <span className="flex-1 text-[14px] text-[var(--chat-text-primary)]">{c.title}</span>
              {selected.has(c.id) && <Check className="size-4 text-[var(--chat-accent)]" />}
            </button>
          ))}
        </div>

        {/* Actions */}
        <div className="flex items-center justify-end gap-2 border-t border-[var(--chat-border)] px-4 py-3">
          <button onClick={onCancel} className="rounded-lg px-3 py-1.5 text-[13px] font-medium text-[var(--chat-text-secondary)] hover:bg-[var(--chat-accent-soft)]">
            Cancel
          </button>
          <button
            onClick={() => onForward(Array.from(selected))}
            disabled={selected.size === 0}
            className="rounded-lg bg-[var(--chat-accent)] px-3 py-1.5 text-[13px] font-medium text-white disabled:opacity-40"
          >
            Forward{selected.size > 0 ? ` (${selected.size})` : ""}
          </button>
        </div>
      </div>
    </div>
  )
}

// ─── ChatEditComposer (inline edit mode) ──────────────────────────────────────

interface ChatEditComposerProps {
  message: ChatMessageData
  onSave: (messageId: string, newText: string) => void
  onCancel: () => void
  className?: string
}

function ChatEditComposer({
  message,
  onSave,
  onCancel,
  className,
}: ChatEditComposerProps) {
  const [value, setValue] = React.useState(message.text || "")

  return (
    <div className={cn("border-t border-[var(--chat-border)]", className)}>
      {/* Edit bar */}
      <div className="flex items-center gap-2 bg-amber-500/10 px-4 py-1.5">
        <span className="text-[12px] font-semibold text-amber-500">Editing message</span>
        <button onClick={onCancel} className="ml-auto text-[12px] text-[var(--chat-text-secondary)] hover:text-[var(--chat-text-primary)]">
          Cancel
        </button>
      </div>
      <div className="flex items-end gap-2 bg-[var(--chat-bg-composer)] px-3 py-2">
        <textarea
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); onSave(message.id, value.trim()) }
            if (e.key === "Escape") onCancel()
          }}
          rows={1}
          autoFocus
          className="flex-1 resize-none rounded-[20px] border border-[var(--chat-border)] bg-[var(--chat-bg-sidebar)] px-4 py-2 text-[15px] text-[var(--chat-text-primary)] outline-none"
        />
        <button
          onClick={() => onSave(message.id, value.trim())}
          disabled={!value.trim()}
          className="flex size-8 items-center justify-center rounded-full bg-[var(--chat-accent)] text-white disabled:opacity-40"
        >
          <Check className="size-4" />
        </button>
      </div>
    </div>
  )
}

// ─── ChatDeletedMessage (placeholder) ─────────────────────────────────────────

interface ChatDeletedMessageProps {
  deletedBy?: string
  className?: string
}

function ChatDeletedMessage({ deletedBy, className }: ChatDeletedMessageProps) {
  return (
    <div className={cn("my-2 flex justify-center", className)}>
      <span className="rounded-lg bg-[var(--chat-bg-sidebar)] px-3 py-1.5 text-[13px] italic text-[var(--chat-text-tertiary)]">
        <Trash2 className="mr-1.5 inline size-3" />
        {deletedBy ? `${deletedBy} deleted this message` : "This message was deleted"}
      </span>
    </div>
  )
}

// ─── ChatPinnedPanel ──────────────────────────────────────────────────────────

interface ChatPinnedPanelProps {
  pinnedMessages: ChatMessageData[]
  onUnpin: (messageId: string) => void
  onJumpTo: (messageId: string) => void
  onClose: () => void
  className?: string
}

function ChatPinnedPanel({
  pinnedMessages,
  onUnpin,
  onJumpTo,
  onClose,
  className,
}: ChatPinnedPanelProps) {
  return (
    <div className={cn("flex h-full w-80 flex-col border-l border-[var(--chat-border-strong)] bg-[var(--chat-bg-sidebar)]", className)}>
      <div className="flex items-center justify-between border-b border-[var(--chat-border)] px-4 py-3">
        <div className="flex items-center gap-2">
          <Pin className="size-4 text-[var(--chat-orange)]" />
          <span className="text-[14px] font-semibold text-[var(--chat-text-primary)]">
            Pinned Messages ({pinnedMessages.length})
          </span>
        </div>
        <button onClick={onClose} className="text-[var(--chat-text-tertiary)] hover:text-[var(--chat-text-primary)]">
          <X className="size-4" />
        </button>
      </div>
      <div className="flex-1 overflow-y-auto">
        {pinnedMessages.map((msg) => (
          <div
            key={msg.id}
            className="border-b border-[var(--chat-border)] px-4 py-3 transition-colors hover:bg-[var(--chat-accent-soft)]"
          >
            <div className="flex items-center justify-between">
              <span className="text-[12px] font-semibold text-[var(--chat-text-secondary)]">{msg.senderName}</span>
              <span className="text-[10px] text-[var(--chat-text-tertiary)]">
                {formatTimestamp(new Date(msg.timestamp))}
              </span>
            </div>
            <p className="mt-0.5 line-clamp-2 text-[13px] text-[var(--chat-text-primary)]">{msg.text}</p>
            <div className="mt-1.5 flex items-center gap-2">
              <button onClick={() => onJumpTo(msg.id)} className="text-[11px] text-[var(--chat-accent)] hover:underline">
                Jump to message
              </button>
              <button onClick={() => onUnpin(msg.id)} className="text-[11px] text-[var(--chat-text-tertiary)] hover:text-[var(--chat-red)]">
                Unpin
              </button>
            </div>
          </div>
        ))}
        {pinnedMessages.length === 0 && (
          <div className="flex h-32 items-center justify-center text-[13px] text-[var(--chat-text-tertiary)]">
            No pinned messages
          </div>
        )}
      </div>
    </div>
  )
}

// ─── ChatNestedThread ─────────────────────────────────────────────────────────

interface ThreadedMessage extends ChatMessageData {
  parentId: string | null
  children: ThreadedMessage[]
  depth: number
  votes?: number
  userVote?: "up" | "down" | null
  isCollapsed?: boolean
}

interface ChatNestedThreadProps {
  messages: ThreadedMessage[]
  maxDepth?: number
  onReply?: (parentId: string) => void
  onVote?: (messageId: string, direction: "up" | "down") => void
  showVotes?: boolean
  className?: string
}

function ChatNestedThread({
  messages,
  maxDepth = 5,
  onReply,
  onVote,
  showVotes = false,
  className,
}: ChatNestedThreadProps) {
  return (
    <div className={cn("space-y-1", className)}>
      {messages.map((msg) => (
        <ThreadMessage
          key={msg.id}
          message={msg}
          maxDepth={maxDepth}
          onReply={onReply}
          onVote={onVote}
          showVotes={showVotes}
        />
      ))}
    </div>
  )
}

function ThreadMessage({
  message,
  maxDepth,
  onReply,
  onVote,
  showVotes,
}: {
  message: ThreadedMessage
  maxDepth: number
  onReply?: (parentId: string) => void
  onVote?: (messageId: string, direction: "up" | "down") => void
  showVotes: boolean
}) {
  const [collapsed, setCollapsed] = React.useState(message.isCollapsed ?? false)
  const atMaxDepth = message.depth >= maxDepth

  return (
    <div style={{ paddingLeft: Math.min(message.depth, maxDepth) * 24 }}>
      <div className="group flex items-start gap-2 rounded-lg px-2 py-1.5 transition-colors hover:bg-[var(--chat-accent-soft)]">
        {/* Thread connector line */}
        {message.depth > 0 && (
          <div className="mt-1 h-full w-0.5 shrink-0 bg-[var(--chat-border)]" />
        )}

        {/* Vote buttons */}
        {showVotes && (
          <div className="flex shrink-0 flex-col items-center gap-0.5">
            <button
              onClick={() => onVote?.(message.id, "up")}
              className={cn("size-5 rounded text-[var(--chat-text-tertiary)] hover:text-[var(--chat-accent)]", message.userVote === "up" && "text-[var(--chat-accent)]")}
            >
              <ArrowUp className="size-3.5 mx-auto" />
            </button>
            <span className="text-[11px] font-semibold tabular-nums text-[var(--chat-text-secondary)]">
              {message.votes ?? 0}
            </span>
            <button
              onClick={() => onVote?.(message.id, "down")}
              className={cn("size-5 rounded text-[var(--chat-text-tertiary)] hover:text-[var(--chat-red)]", message.userVote === "down" && "text-[var(--chat-red)]")}
            >
              <ArrowDown className="size-3.5 mx-auto" />
            </button>
          </div>
        )}

        {/* Content */}
        <div className="min-w-0 flex-1">
          <div className="flex items-center gap-2">
            <span className="text-[13px] font-semibold text-[var(--chat-text-primary)]">{message.senderName}</span>
            <span className="text-[11px] text-[var(--chat-text-tertiary)]">
              {formatTimestamp(new Date(message.timestamp))}
            </span>
          </div>
          <p className="text-[14px] leading-relaxed text-[var(--chat-text-primary)]">{message.text}</p>
          <div className="mt-1 flex items-center gap-3">
            {!atMaxDepth && (
              <button onClick={() => onReply?.(message.id)} className="text-[11px] font-medium text-[var(--chat-text-secondary)] hover:text-[var(--chat-accent)]">
                Reply
              </button>
            )}
            {message.children.length > 0 && (
              <button
                onClick={() => setCollapsed(!collapsed)}
                className="flex items-center gap-0.5 text-[11px] font-medium text-[var(--chat-text-secondary)] hover:text-[var(--chat-text-primary)]"
              >
                {collapsed ? <ChevronRight className="size-3" /> : <ChevronDown className="size-3" />}
                {message.children.length} {message.children.length === 1 ? "reply" : "replies"}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Children */}
      {!collapsed && message.children.length > 0 && (
        <div className="border-l-2 border-[var(--chat-border)] ml-3">
          {message.children.map((child) => (
            <ThreadMessage
              key={child.id}
              message={child}
              maxDepth={maxDepth}
              onReply={onReply}
              onVote={onVote}
              showVotes={showVotes}
            />
          ))}
        </div>
      )}

      {atMaxDepth && message.children.length > 0 && (
        <button className="ml-6 mt-1 text-[11px] text-[var(--chat-accent)] hover:underline">
          Continue thread \u2192
        </button>
      )}
    </div>
  )
}

// ─── ChatSearch ───────────────────────────────────────────────────────────────

interface SearchResult {
  messageId: string
  conversationId?: string
  conversationName?: string
  senderName: string
  snippet: string
  timestamp: Date | number
}

interface ChatSearchProps {
  onSearch: (query: string) => SearchResult[] | Promise<SearchResult[]>
  onSelect: (result: SearchResult) => void
  onClose: () => void
  className?: string
}

function ChatSearch({ onSearch, onSelect, onClose, className }: ChatSearchProps) {
  const [query, setQuery] = React.useState("")
  const [results, setResults] = React.useState<SearchResult[]>([])
  const inputRef = React.useRef<HTMLInputElement>(null)

  React.useEffect(() => {
    inputRef.current?.focus()
  }, [])

  React.useEffect(() => {
    if (!query.trim()) { setResults([]); return }
    const timeout = setTimeout(async () => {
      const r = await onSearch(query)
      setResults(r)
    }, 200)
    return () => clearTimeout(timeout)
  }, [query, onSearch])

  React.useEffect(() => {
    const handler = (e: KeyboardEvent) => { if (e.key === "Escape") onClose() }
    document.addEventListener("keydown", handler)
    return () => document.removeEventListener("keydown", handler)
  }, [onClose])

  return (
    <div className={cn("fixed inset-0 z-50 flex items-start justify-center pt-[15vh] bg-black/50", className)}>
      <div className="w-full max-w-lg overflow-hidden rounded-xl border border-[var(--chat-border-strong)] bg-[var(--chat-bg-sidebar)] shadow-[var(--chat-shadow-lg)]">
        {/* Search input */}
        <div className="flex items-center gap-3 border-b border-[var(--chat-border)] px-4 py-3">
          <Search className="size-4 text-[var(--chat-text-tertiary)]" />
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search messages..."
            className="flex-1 bg-transparent text-[15px] text-[var(--chat-text-primary)] placeholder:text-[var(--chat-text-tertiary)] outline-none"
          />
          <kbd className="rounded border border-[var(--chat-border)] px-1.5 py-0.5 text-[10px] text-[var(--chat-text-tertiary)]">ESC</kbd>
        </div>

        {/* Results */}
        <div className="max-h-80 overflow-y-auto">
          {results.map((r) => (
            <button
              key={r.messageId}
              onClick={() => { onSelect(r); onClose() }}
              className="flex w-full flex-col gap-0.5 border-b border-[var(--chat-border)] px-4 py-2.5 text-left transition-colors hover:bg-[var(--chat-accent-soft)]"
            >
              <div className="flex items-center gap-2">
                <span className="text-[13px] font-semibold text-[var(--chat-text-primary)]">{r.senderName}</span>
                {r.conversationName && (
                  <span className="text-[11px] text-[var(--chat-text-tertiary)]">in {r.conversationName}</span>
                )}
                <span className="ml-auto text-[11px] text-[var(--chat-text-tertiary)]">
                  {formatTimestamp(new Date(r.timestamp))}
                </span>
              </div>
              <p className="truncate text-[13px] text-[var(--chat-text-secondary)]">{r.snippet}</p>
            </button>
          ))}
          {query.trim() && results.length === 0 && (
            <div className="flex h-20 items-center justify-center text-[13px] text-[var(--chat-text-tertiary)]">
              No results found
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  ChatForwardDialog,
  ChatEditComposer,
  ChatDeletedMessage,
  ChatPinnedPanel,
  ChatNestedThread,
  ChatSearch,
}
export type {
  Conversation,
  ChatForwardDialogProps,
  ChatEditComposerProps,
  ChatDeletedMessageProps,
  ChatPinnedPanelProps,
  ThreadedMessage,
  ChatNestedThreadProps,
  SearchResult,
  ChatSearchProps,
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import {
  MessageSquare,
  Search,
  Phone,
  X,
  ChevronLeft,
  Plus,
  Minimize2,
  Pin,
} from "lucide-react"
import type { ChatMessageData, ChatUser, ChatTheme, TypingUser } from "./types"
import { ChatProvider } from "./chat"
import { ChatMessages, ChatComposer } from "./chat"

// ─── Shared: ChatHeader ───────────────────────────────────────────────────────

interface ChatHeaderProps {
  title: string
  subtitle?: string
  avatar?: React.ReactNode
  actions?: React.ReactNode
  onBack?: () => void
  className?: string
}

function ChatHeader({ title, subtitle, avatar, actions, onBack, className }: ChatHeaderProps) {
  return (
    <header className={cn("sticky top-0 z-10 flex items-center gap-3 border-b border-[var(--chat-border)] bg-[var(--chat-bg-header)] px-4 py-3 backdrop-blur-[20px] backdrop-saturate-[180%]", className)}>
      {onBack && (
        <button onClick={onBack} className="mr-1 text-[var(--chat-text-secondary)] hover:text-[var(--chat-text-primary)]">
          <ChevronLeft className="size-5" />
        </button>
      )}
      {avatar}
      <div className="flex min-w-0 flex-1 flex-col">
        <span className="truncate text-[15px] font-semibold tracking-[-0.02em] text-[var(--chat-text-primary)]">{title}</span>
        {subtitle && <span className="truncate text-[12px] text-[var(--chat-text-secondary)]">{subtitle}</span>}
      </div>
      {actions}
    </header>
  )
}

// ─── Shared: Sidebar conversation item ────────────────────────────────────────

interface SidebarConversation {
  id: string
  title: string
  avatar?: string
  lastMessage?: string
  lastMessageTime?: string
  unreadCount?: number
  presence?: "online" | "away" | "offline"
  isGroup?: boolean
}

function ConversationItem({
  convo,
  isActive,
  onClick,
}: {
  convo: SidebarConversation
  isActive: boolean
  onClick: () => void
}) {
  return (
    <button
      onClick={onClick}
      className={cn(
        "mx-1 flex w-[calc(100%-8px)] items-center gap-3 rounded-xl px-3 py-2.5 text-left transition-colors",
        isActive ? "bg-[var(--chat-accent-soft)]" : "hover:bg-[var(--chat-accent-soft)]"
      )}
    >
      <div className="relative shrink-0">
        <div className="flex size-11 items-center justify-center rounded-full bg-[var(--chat-bubble-incoming)] text-[13px] font-semibold text-[var(--chat-text-secondary)]">
          {convo.title.charAt(0).toUpperCase()}
        </div>
        {convo.presence === "online" && (
          <div className="absolute -bottom-0.5 -right-0.5 size-[10px] rounded-full border-2 border-[var(--chat-bg-sidebar)] bg-[var(--chat-green)]" />
        )}
      </div>
      <div className="min-w-0 flex-1">
        <div className="flex items-center justify-between">
          <span className="truncate text-[15px] font-semibold text-[var(--chat-text-primary)]">{convo.title}</span>
          {convo.lastMessageTime && (
            <span className="ml-2 shrink-0 text-[11px] text-[var(--chat-text-tertiary)]">{convo.lastMessageTime}</span>
          )}
        </div>
        <div className="flex items-center justify-between">
          <span className="truncate text-[13px] text-[var(--chat-text-secondary)]">{convo.lastMessage}</span>
          {(convo.unreadCount ?? 0) > 0 && (
            <span className="ml-2 flex size-[18px] shrink-0 items-center justify-center rounded-full bg-[var(--chat-red)] text-[11px] font-bold text-white">
              {convo.unreadCount! > 99 ? "99+" : convo.unreadCount}
            </span>
          )}
        </div>
      </div>
    </button>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
// LAYOUT 1: FullMessenger (Slack/Discord)
// ═══════════════════════════════════════════════════════════════════════════════

interface FullMessengerProps {
  currentUser: ChatUser
  theme?: ChatTheme
  conversations: SidebarConversation[]
  activeConversationId?: string
  onSelectConversation: (id: string) => void
  messages: ChatMessageData[]
  typingUsers?: TypingUser[]
  onSend: (text: string) => void
  title?: string
  subtitle?: string
  className?: string
}

function FullMessenger({
  currentUser,
  theme = "lunar",
  conversations,
  activeConversationId,
  onSelectConversation,
  messages,
  typingUsers,
  onSend,
  title = "Messages",
  subtitle,
  className,
}: FullMessengerProps) {
  const activeConvo = conversations.find((c) => c.id === activeConversationId)

  return (
    <ChatProvider currentUser={currentUser} theme={theme}>
      <div className={cn("flex h-full bg-[var(--chat-bg-app)]", className)}>
        {/* Sidebar — 320px */}
        <aside className="flex w-80 shrink-0 flex-col border-r border-[var(--chat-border-strong)] bg-[var(--chat-bg-sidebar)]">
          <div className="flex items-center justify-between px-4 py-3">
            <span className="text-[15px] font-semibold text-[var(--chat-text-primary)]">{title}</span>
            <button className="text-[var(--chat-text-secondary)] hover:text-[var(--chat-text-primary)]">
              <Plus className="size-5" />
            </button>
          </div>
          {/* Search */}
          <div className="px-3 pb-2">
            <div className="flex items-center gap-2 rounded-[10px] bg-[var(--chat-bg-main)] px-3 py-2 opacity-50">
              <Search className="size-3.5" />
              <span className="text-[14px] text-[var(--chat-text-tertiary)]">Search</span>
            </div>
          </div>
          {/* Conversation list */}
          <div className="flex-1 overflow-y-auto py-1">
            {conversations.map((c) => (
              <ConversationItem
                key={c.id}
                convo={c}
                isActive={c.id === activeConversationId}
                onClick={() => onSelectConversation(c.id)}
              />
            ))}
          </div>
        </aside>

        {/* Main panel */}
        <main className="flex flex-1 flex-col bg-[var(--chat-bg-main)]">
          {activeConvo ? (
            <>
              <ChatHeader
                title={activeConvo.title}
                subtitle={subtitle || (activeConvo.isGroup ? "Group" : undefined)}
                avatar={
                  <div className="relative">
                    <div className="flex size-10 items-center justify-center rounded-full bg-[var(--chat-bubble-incoming)] text-sm font-semibold text-[var(--chat-text-primary)]">
                      {activeConvo.title.charAt(0).toUpperCase()}
                    </div>
                    {activeConvo.presence === "online" && (
                      <div className="absolute -bottom-0.5 -right-0.5 size-[10px] rounded-full border-2 border-[var(--chat-bg-main)] bg-[var(--chat-green)]" />
                    )}
                  </div>
                }
                actions={
                  <div className="flex items-center gap-1">
                    <button className="flex size-8 items-center justify-center rounded-lg text-[var(--chat-text-secondary)] hover:bg-[var(--chat-accent-soft)]"><Phone className="size-4" /></button>
                    <button className="flex size-8 items-center justify-center rounded-lg text-[var(--chat-text-secondary)] hover:bg-[var(--chat-accent-soft)]"><Search className="size-4" /></button>
                    <button className="flex size-8 items-center justify-center rounded-lg text-[var(--chat-text-secondary)] hover:bg-[var(--chat-accent-soft)]"><Pin className="size-4" /></button>
                  </div>
                }
              />
              <ChatMessages messages={messages} typingUsers={typingUsers} />
              <ChatComposer onSend={onSend} />
            </>
          ) : (
            <div className="flex flex-1 items-center justify-center">
              <div className="text-center">
                <MessageSquare className="mx-auto mb-3 size-12 text-[var(--chat-text-tertiary)]" />
                <p className="text-[15px] font-medium text-[var(--chat-text-secondary)]">Select a conversation</p>
              </div>
            </div>
          )}
        </main>
      </div>
    </ChatProvider>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
// LAYOUT 2: ChatWidget (Intercom-style floating)
// ═══════════════════════════════════════════════════════════════════════════════

interface ChatWidgetProps {
  currentUser: ChatUser
  theme?: ChatTheme
  messages: ChatMessageData[]
  onSend: (text: string) => void
  title?: string
  subtitle?: string
  greeting?: string
  position?: "bottom-right" | "bottom-left"
  className?: string
}

function ChatWidget({
  currentUser,
  theme = "lunar",
  messages,
  onSend,
  title = "Support",
  subtitle = "We typically reply in minutes",
  position = "bottom-right",
  className,
}: ChatWidgetProps) {
  const [isOpen, setIsOpen] = React.useState(false)

  return (
    <ChatProvider currentUser={currentUser} theme={theme}>
      <div className={cn("fixed z-50", position === "bottom-right" ? "bottom-5 right-5" : "bottom-5 left-5", className)}>
        {/* Chat window */}
        {isOpen && (
          <div className="mb-3 flex h-[500px] w-[380px] flex-col overflow-hidden rounded-2xl border border-[var(--chat-border-strong)] bg-[var(--chat-bg-main)] shadow-[var(--chat-shadow-lg)]">
            <ChatHeader
              title={title}
              subtitle={subtitle}
              avatar={
                <div className="flex size-9 items-center justify-center rounded-full bg-[var(--chat-accent)] text-[12px] font-bold text-white">
                  <MessageSquare className="size-4" />
                </div>
              }
              actions={
                <button onClick={() => setIsOpen(false)} className="text-[var(--chat-text-secondary)] hover:text-[var(--chat-text-primary)]">
                  <Minimize2 className="size-4" />
                </button>
              }
            />
            <ChatMessages messages={messages} />
            <ChatComposer onSend={onSend} placeholder="Type a message..." />
          </div>
        )}

        {/* FAB */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="flex size-14 items-center justify-center rounded-full bg-[var(--chat-accent)] text-white shadow-[var(--chat-shadow-lg)] transition-transform hover:scale-105 active:scale-95"
          aria-label={isOpen ? "Close chat" : "Open chat"}
        >
          {isOpen ? <X className="size-6" /> : <MessageSquare className="size-6" />}
        </button>
      </div>
    </ChatProvider>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
// LAYOUT 3: InlineChat (Comments section)
// ═══════════════════════════════════════════════════════════════════════════════

interface InlineChatProps {
  currentUser: ChatUser
  theme?: ChatTheme
  messages: ChatMessageData[]
  onSend: (text: string) => void
  placeholder?: string
  maxHeight?: number
  className?: string
}

function InlineChat({
  currentUser,
  theme = "lunar",
  messages,
  onSend,
  placeholder = "Add a comment...",
  maxHeight = 600,
  className,
}: InlineChatProps) {
  return (
    <ChatProvider currentUser={currentUser} theme={theme}>
      <div className={cn("flex flex-col overflow-hidden rounded-xl border border-[var(--chat-border-strong)] bg-[var(--chat-bg-main)]", className)} style={{ maxHeight }}>
        <ChatMessages messages={messages} />
        <ChatComposer onSend={onSend} placeholder={placeholder} />
      </div>
    </ChatProvider>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
// LAYOUT 5: ChatBoard (Forum/Discussion)
// ═══════════════════════════════════════════════════════════════════════════════

interface Topic {
  id: string
  title: string
  author: string
  replyCount: number
  lastActivity: string
  isPinned?: boolean
  tags?: string[]
}

interface ChatBoardProps {
  currentUser: ChatUser
  theme?: ChatTheme
  topics: Topic[]
  activeTopic?: Topic
  onSelectTopic: (id: string) => void
  onBack?: () => void
  children?: React.ReactNode
  className?: string
}

function ChatBoard({
  currentUser,
  theme = "lunar",
  topics,
  activeTopic,
  onSelectTopic,
  onBack,
  children,
  className,
}: ChatBoardProps) {
  return (
    <ChatProvider currentUser={currentUser} theme={theme}>
      <div className={cn("flex h-full flex-col bg-[var(--chat-bg-main)]", className)}>
        {activeTopic ? (
          <>
            <ChatHeader title={activeTopic.title} subtitle={`${activeTopic.replyCount} replies`} onBack={onBack} />
            <div className="flex-1 overflow-y-auto px-4 py-4">
              <div className="mx-auto max-w-3xl">{children}</div>
            </div>
          </>
        ) : (
          <>
            <ChatHeader title="Discussions" actions={
              <button className="flex size-8 items-center justify-center rounded-lg bg-[var(--chat-accent)] text-white"><Plus className="size-4" /></button>
            } />
            <div className="flex-1 overflow-y-auto">
              {topics.map((t) => (
                <button
                  key={t.id}
                  onClick={() => onSelectTopic(t.id)}
                  className="flex w-full items-start gap-3 border-b border-[var(--chat-border)] px-4 py-3 text-left transition-colors hover:bg-[var(--chat-accent-soft)]"
                >
                  {t.isPinned && <Pin className="mt-0.5 size-3.5 shrink-0 text-[var(--chat-orange)]" />}
                  <div className="min-w-0 flex-1">
                    <p className="text-[14px] font-semibold text-[var(--chat-text-primary)]">{t.title}</p>
                    <div className="mt-0.5 flex items-center gap-2 text-[12px] text-[var(--chat-text-secondary)]">
                      <span>{t.author}</span>
                      <span>\u00B7</span>
                      <span>{t.replyCount} replies</span>
                      <span>\u00B7</span>
                      <span>{t.lastActivity}</span>
                    </div>
                    {t.tags && t.tags.length > 0 && (
                      <div className="mt-1 flex gap-1">
                        {t.tags.map((tag) => (
                          <span key={tag} className="rounded-full bg-[var(--chat-accent-soft)] px-2 py-0.5 text-[11px] font-medium text-[var(--chat-accent)]">{tag}</span>
                        ))}
                      </div>
                    )}
                  </div>
                </button>
              ))}
            </div>
          </>
        )}
      </div>
    </ChatProvider>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
// LAYOUT 6: LiveChat (Twitch/YouTube live stream)
// ═══════════════════════════════════════════════════════════════════════════════

interface LiveChatProps {
  currentUser: ChatUser
  theme?: ChatTheme
  messages: ChatMessageData[]
  onSend: (text: string) => void
  title?: string
  viewerCount?: number
  className?: string
}

function LiveChat({
  currentUser,
  theme = "ember",
  messages,
  onSend,
  title = "Live Chat",
  viewerCount,
  className,
}: LiveChatProps) {
  return (
    <ChatProvider currentUser={currentUser} theme={theme} messageGroupingInterval={0}>
      <div className={cn("flex h-full flex-col bg-[var(--chat-bg-main)]", className)}>
        <div className="flex items-center justify-between border-b border-[var(--chat-border)] px-3 py-2">
          <span className="text-[14px] font-semibold text-[var(--chat-text-primary)]">{title}</span>
          {viewerCount !== undefined && (
            <span className="flex items-center gap-1 text-[12px] text-[var(--chat-text-secondary)]">
              <span className="size-1.5 rounded-full bg-[var(--chat-red)]" />
              {viewerCount.toLocaleString()} watching
            </span>
          )}
        </div>
        <ChatMessages messages={messages} />
        <ChatComposer onSend={onSend} placeholder="Send a message..." />
      </div>
    </ChatProvider>
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

const ChatConversationItem = ConversationItem

export {
  ChatHeader,
  ChatConversationItem,
  FullMessenger,
  ChatWidget,
  InlineChat,
  ChatBoard,
  LiveChat,
}
export type {
  ChatHeaderProps,
  SidebarConversation,
  FullMessengerProps,
  ChatWidgetProps,
  InlineChatProps,
  Topic,
  ChatBoardProps,
  LiveChatProps,
}

css:
/* ═══════════════════════════════════════════════════════════════════════
   chatcn — Three-Theme System (Lunar / Aurora / Ember)
   From chatcn-themes.md — all CSS variables per theme
   Applied via data-chat-theme attribute on ChatProvider wrapper
   ═══════════════════════════════════════════════════════════════════════ */

/* ─── Shared font stacks (legally clean per themes doc §0) ─────────── */
:root {
  --chat-font-sans: system-ui, -apple-system, BlinkMacSystemFont,
                    "Segoe UI", Roboto, "Helvetica Neue", sans-serif;
  --chat-font-mono: "SF Mono", "JetBrains Mono", "Fira Code",
                    ui-monospace, monospace;
}

/* ═══ THEME 1: LUNAR (Default) ═══════════════════════════════════════ */
/* "Calm midnight workspace." — Indigo accent, Zinc neutrals            */

[data-chat-theme="lunar"] {
  /* Light mode */
  --chat-bg-app:              #FAFAFA;
  --chat-bg-sidebar:          #F4F4F5;
  --chat-bg-main:             #FFFFFF;
  --chat-bg-header:           rgba(255, 255, 255, 0.75);
  --chat-bg-composer:         rgba(255, 255, 255, 0.82);

  --chat-bubble-outgoing:     #6366F1;
  --chat-bubble-outgoing-text: #FFFFFF;
  --chat-bubble-incoming:     #F4F4F5;
  --chat-bubble-incoming-text: #18181B;

  --chat-accent:              #6366F1;
  --chat-accent-soft:         rgba(99, 102, 241, 0.08);
  --chat-green:               #22C55E;
  --chat-orange:              #F59E0B;
  --chat-red:                 #EF4444;

  --chat-text-primary:        #18181B;
  --chat-text-secondary:      #71717A;
  --chat-text-tertiary:       #A1A1AA;
  --chat-border:              rgba(0, 0, 0, 0.06);
  --chat-border-strong:       rgba(0, 0, 0, 0.10);

  --chat-shadow-sm:           0 1px 2px rgba(0, 0, 0, 0.04);
  --chat-shadow-md:           0 4px 12px rgba(0, 0, 0, 0.06);
  --chat-shadow-lg:           0 8px 30px rgba(0, 0, 0, 0.08);
  --chat-shadow-toolbar:      0 2px 16px rgba(0, 0, 0, 0.12);

  --chat-bubble-radius:       14px;
  --chat-bubble-radius-grouped: 4px;
  --chat-input-radius:        20px;
  --chat-spacing-messages:    14px;
  --chat-spacing-grouped:     2px;

  --chat-ease:                cubic-bezier(0.25, 0.1, 0.25, 1.0);
  --chat-duration-fast:       150ms;
  --chat-duration-normal:     250ms;
}

/* Lunar Dark */
.dark [data-chat-theme="lunar"],
[data-chat-theme="lunar"].dark {
  --chat-bg-app:              #09090B;
  --chat-bg-sidebar:          #18181B;
  --chat-bg-main:             #09090B;
  --chat-bg-header:           rgba(24, 24, 27, 0.75);
  --chat-bg-composer:         rgba(24, 24, 27, 0.82);

  --chat-bubble-outgoing:     #818CF8;
  --chat-bubble-outgoing-text: #FFFFFF;
  --chat-bubble-incoming:     #27272A;
  --chat-bubble-incoming-text: #FAFAFA;

  --chat-accent:              #818CF8;
  --chat-accent-soft:         rgba(129, 140, 248, 0.10);
  --chat-green:               #4ADE80;
  --chat-orange:              #FBBF24;
  --chat-red:                 #F87171;

  --chat-text-primary:        #FAFAFA;
  --chat-text-secondary:      #A1A1AA;
  --chat-text-tertiary:       #52525B;
  --chat-border:              rgba(255, 255, 255, 0.06);
  --chat-border-strong:       rgba(255, 255, 255, 0.10);

  --chat-shadow-sm:           0 1px 3px rgba(0, 0, 0, 0.20);
  --chat-shadow-md:           0 4px 16px rgba(0, 0, 0, 0.30);
  --chat-shadow-lg:           0 8px 40px rgba(0, 0, 0, 0.40);
  --chat-shadow-toolbar:      0 2px 20px rgba(0, 0, 0, 0.40);
}

/* ═══ THEME 2: AURORA ════════════════════════════════════════════════ */
/* "Soft morning light." — Teal accent, warm Stone/Ivory tones          */

[data-chat-theme="aurora"] {
  --chat-bg-app:              #FFFBF5;
  --chat-bg-sidebar:          #FFF8F0;
  --chat-bg-main:             #FFFBF5;
  --chat-bg-header:           rgba(255, 251, 245, 0.80);
  --chat-bg-composer:         rgba(255, 251, 245, 0.85);

  /* Aurora uses outlined bubbles — subtle teal wash */
  --chat-bubble-outgoing:     rgba(13, 148, 136, 0.10);
  --chat-bubble-outgoing-text: #1C1917;
  --chat-bubble-incoming:     rgba(0, 0, 0, 0.05);
  --chat-bubble-incoming-text: #1C1917;

  --chat-accent:              #0D9488;
  --chat-accent-soft:         rgba(13, 148, 136, 0.06);
  --chat-green:               #16A34A;
  --chat-orange:              #EA580C;
  --chat-red:                 #DC2626;

  --chat-text-primary:        #1C1917;
  --chat-text-secondary:      #78716C;
  --chat-text-tertiary:       #A8A29E;
  --chat-border:              rgba(120, 113, 108, 0.10);
  --chat-border-strong:       rgba(120, 113, 108, 0.18);

  --chat-shadow-sm:           0 1px 2px rgba(120, 113, 108, 0.06);
  --chat-shadow-md:           0 4px 20px rgba(120, 113, 108, 0.08);
  --chat-shadow-lg:           0 12px 40px rgba(120, 113, 108, 0.08);
  --chat-shadow-toolbar:      0 4px 20px rgba(120, 113, 108, 0.10);

  --chat-bubble-radius:       18px;
  --chat-bubble-radius-grouped: 6px;
  --chat-input-radius:        24px;
  --chat-spacing-messages:    16px;
  --chat-spacing-grouped:     3px;

  --chat-ease:                cubic-bezier(0.34, 1.56, 0.64, 1);
  --chat-duration-fast:       180ms;
  --chat-duration-normal:     280ms;
}

/* Aurora Dark */
.dark [data-chat-theme="aurora"],
[data-chat-theme="aurora"].dark {
  --chat-bg-app:              #0C0A09;
  --chat-bg-sidebar:          #1C1917;
  --chat-bg-main:             #0C0A09;
  --chat-bg-header:           rgba(28, 25, 23, 0.78);
  --chat-bg-composer:         rgba(28, 25, 23, 0.85);

  --chat-bubble-outgoing:     rgba(45, 212, 191, 0.08);
  --chat-bubble-outgoing-text: #FAFAF9;
  --chat-bubble-incoming:     rgba(255, 255, 255, 0.04);
  --chat-bubble-incoming-text: #FAFAF9;

  --chat-accent:              #2DD4BF;
  --chat-accent-soft:         rgba(45, 212, 191, 0.08);

  --chat-text-primary:        #FAFAF9;
  --chat-text-secondary:      #A8A29E;
  --chat-text-tertiary:       #57534E;
  --chat-border:              rgba(255, 255, 255, 0.06);
  --chat-border-strong:       rgba(255, 255, 255, 0.10);

  --chat-shadow-sm:           0 1px 3px rgba(0, 0, 0, 0.20);
  --chat-shadow-md:           0 4px 16px rgba(0, 0, 0, 0.25);
  --chat-shadow-lg:           0 8px 40px rgba(0, 0, 0, 0.35);
  --chat-shadow-toolbar:      0 2px 20px rgba(0, 0, 0, 0.35);
}

/* Aurora outlined bubble borders — use outline to avoid cascading into child elements */
[data-chat-theme="aurora"] .chat-bubble {
  outline: 1.5px solid rgba(13, 148, 136, 0.25);
  outline-offset: -1.5px;
}
.dark [data-chat-theme="aurora"] .chat-bubble,
[data-chat-theme="aurora"].dark .chat-bubble {
  outline: 1.5px solid rgba(45, 212, 191, 0.20);
  outline-offset: -1.5px;
}

/* ═══ THEME 3: EMBER ═════════════════════════════════════════════════ */
/* "Dense. Fast. No bullshit." — Orange accent, Slate neutrals, flat    */

[data-chat-theme="ember"] {
  --chat-bg-app:              #FFFFFF;
  --chat-bg-sidebar:          #F8FAFC;
  --chat-bg-main:             #FFFFFF;
  --chat-bg-header:           #FFFFFF;
  --chat-bg-composer:         #FFFFFF;

  /* Ember: subtle background for visual separation */
  --chat-bubble-outgoing:     rgba(249, 115, 22, 0.04);
  --chat-bubble-outgoing-text: #0F172A;
  --chat-bubble-incoming:     rgba(0, 0, 0, 0.02);
  --chat-bubble-incoming-text: #0F172A;

  --chat-accent:              #F97316;
  --chat-accent-soft:         rgba(249, 115, 22, 0.06);
  --chat-green:               #22C55E;
  --chat-orange:              #F97316;
  --chat-red:                 #EF4444;

  --chat-text-primary:        #0F172A;
  --chat-text-secondary:      #64748B;
  --chat-text-tertiary:       #94A3B8;
  --chat-border:              #E2E8F0;
  --chat-border-strong:       #CBD5E1;

  --chat-shadow-sm:           none;
  --chat-shadow-md:           none;
  --chat-shadow-lg:           none;
  --chat-shadow-toolbar:      none;

  --chat-bubble-radius:       0px;
  --chat-bubble-radius-grouped: 0px;
  --chat-input-radius:        8px;
  --chat-spacing-messages:    8px;
  --chat-spacing-grouped:     0px;

  --chat-ease:                cubic-bezier(0.16, 1, 0.3, 1);
  --chat-duration-fast:       100ms;
  --chat-duration-normal:     150ms;
}

/* Ember Dark */
.dark [data-chat-theme="ember"],
[data-chat-theme="ember"].dark {
  --chat-bg-app:              #0B0F19;
  --chat-bg-sidebar:          #111827;
  --chat-bg-main:             #0B0F19;
  --chat-bg-header:           #111827;
  --chat-bg-composer:         #111827;

  --chat-bubble-outgoing:     rgba(251, 146, 60, 0.06);
  --chat-bubble-outgoing-text: #F8FAFC;
  --chat-bubble-incoming:     rgba(255, 255, 255, 0.03);
  --chat-bubble-incoming-text: #F8FAFC;

  --chat-accent:              #FB923C;
  --chat-accent-soft:         rgba(251, 146, 60, 0.08);

  --chat-text-primary:        #F8FAFC;
  --chat-text-secondary:      #94A3B8;
  --chat-text-tertiary:       #475569;
  --chat-border:              rgba(255, 255, 255, 0.08);
  --chat-border-strong:       rgba(255, 255, 255, 0.12);
}

/* Ember flat message style — left border bar instead of bubble */
[data-chat-theme="ember"] .chat-bubble {
  border-radius: 0 !important;
  border-left: 3px solid var(--chat-accent);
  padding: 6px 16px 6px 12px;
}

/* Ember: message rows get hover bg for visibility */
[data-chat-theme="ember"] .chat-message:hover {
  background: var(--chat-accent-soft);
  border-radius: 4px;
}

/* Ember: no frosted glass — solid backgrounds */
[data-chat-theme="ember"] .chat-composer {
  backdrop-filter: none;
  -webkit-backdrop-filter: none;
}

/* ═══ THEME 4: MIDNIGHT (True OLED Black — Dark Only) ═══════════════ */
/* "Void. Pure content. Nothing else." — Blue accent, true #000000       */

[data-chat-theme="midnight"] {
  --chat-bg-app:              #000000;
  --chat-bg-sidebar:          #0A0A0A;
  --chat-bg-main:             #000000;
  --chat-bg-header:           rgba(10, 10, 10, 0.80);
  --chat-bg-composer:         rgba(10, 10, 10, 0.85);

  --chat-bubble-outgoing:     rgba(59, 130, 246, 0.20);
  --chat-bubble-outgoing-text: #FFFFFF;
  --chat-bubble-incoming:     rgba(255, 255, 255, 0.06);
  --chat-bubble-incoming-text: #E5E5E5;

  --chat-accent:              #3B82F6;
  --chat-accent-soft:         rgba(59, 130, 246, 0.10);
  --chat-green:               #22C55E;
  --chat-orange:              #F59E0B;
  --chat-red:                 #EF4444;

  --chat-text-primary:        #FFFFFF;
  --chat-text-secondary:      #737373;
  --chat-text-tertiary:       #404040;

  --chat-border:              rgba(255, 255, 255, 0.04);
  --chat-border-strong:       rgba(255, 255, 255, 0.08);

  --chat-bg-content-card:     #111111;
  --chat-bg-code:             #111111;

  --chat-shadow-sm:           none;
  --chat-shadow-md:           none;
  --chat-shadow-lg:           none;
  --chat-shadow-toolbar:      0 0 0 1px rgba(255, 255, 255, 0.08);

  --chat-bubble-radius:       16px;
  --chat-bubble-radius-grouped: 4px;
  --chat-input-radius:        20px;
  --chat-spacing-messages:    16px;
  --chat-spacing-grouped:     2px;

  --chat-ease:                cubic-bezier(0.25, 0.1, 0.25, 1.0);
  --chat-duration-fast:       150ms;
  --chat-duration-normal:     250ms;
}

/* Midnight: reaction glow on hover */
[data-chat-theme="midnight"] .chat-reaction-pop:hover {
  box-shadow: 0 0 8px rgba(59, 130, 246, 0.15);
}

/* ─── Content Card Variables (per-theme backgrounds for embedded content) ─── */

/* Lunar */
[data-chat-theme="lunar"] {
  --chat-bg-content-card: #F4F4F5;
  --chat-bg-code: #F4F4F5;
}
.dark [data-chat-theme="lunar"],
[data-chat-theme="lunar"].dark {
  --chat-bg-content-card: #18181B;
  --chat-bg-code: #18181B;
}

/* Aurora */
[data-chat-theme="aurora"] {
  --chat-bg-content-card: #FFFFFF;
  --chat-bg-code: #F5F0EB;
}
.dark [data-chat-theme="aurora"],
[data-chat-theme="aurora"].dark {
  --chat-bg-content-card: #1C1917;
  --chat-bg-code: #1C1917;
}

/* Aurora content cards need extra definition on light bg */
[data-chat-theme="aurora"] .chat-content-card {
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.06);
}

/* Ember */
[data-chat-theme="ember"] {
  --chat-bg-content-card: #F8FAFC;
  --chat-bg-code: #F1F5F9;
}
.dark [data-chat-theme="ember"],
[data-chat-theme="ember"].dark {
  --chat-bg-content-card: #111827;
  --chat-bg-code: #0F172A;
}

/* Midnight already defined above */

/* ─── Shared content card class ─────────────────────────────────────── */
@layer base {
  .chat-content-card {
    background: var(--chat-bg-content-card);
    border: 1px solid var(--chat-border-strong);
    border-radius: 12px;
    overflow: hidden;
  }
}

/* ─── Drag-and-drop upload overlay ──────────────────────────────────── */
@layer base {
  .chat-drop-overlay {
    position: absolute;
    inset: 0;
    z-index: 50;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--chat-accent-soft);
    border: 2px dashed var(--chat-accent);
    border-radius: 12px;
    backdrop-filter: blur(4px);
  }
}
[data-chat-theme="ember"] .chat-drop-overlay {
  border-radius: 4px;
}
